from flask import Flask, jsonify, request
import jwt
from datetime import timedelta

app = Flask(__name__)

# Set the secret key used for signing JWT tokens
app.config['JWT_SECRET_KEY'] = 'your-secret-key'

@app.route('/login', methods=['POST'])
def login():
    # Check if the username and password are correct
    if request.json.get('username') == 'admin' and request.json.get('password') == 'password':
        # Generate a JWT token with an expiration time of 1 hour
        token = jwt.encode({'user_id': 1, 'exp': timedelta(hours=1)}, app.config['JWT_SECRET_KEY'])
        return jsonify({'token': token})
    else:
        return jsonify({'error': 'Invalid username or password'}), 401

@app.route('/protected', methods=['GET'])
def protected():
    # Check if the request has a JWT token and verify it
    token = request.headers.get('Authorization')
    if not token:
        return jsonify({'error': 'Token is missing'}), 401
    
    try:
        payload = jwt.decode(token, app.config['JWT_SECRET_KEY'])
    except jwt.ExpiredSignatureError:
        return jsonify({'error': 'Token has expired'}), 401
    
    # If the token is valid, return a message
    return jsonify({'message': 'Token is valid'})